class Solution {
public:
    Solution(vector<int>& w) {
        int sum = 0;
        for (int i : w) sum += i;
        for (int i = 0; i < w.size(); i++) {
            w[i] = (long long)w[i] * (sum - w[i]) + i;
            sum--;
        }
    }

    int pickIndex() {
        int target = rand() % (int)(1e9) + 1;
        for (int i = 0; i < w.size(); i++) {
            if (target <= w[i]) return i;
        }
        return -1; // This should never happen
    }
};
```

